data.query:
mutation FulfillmentOrderHold($fulfillmentHold: FulfillmentOrderHoldInput!, $id: ID!) {
    fulfillmentOrderHold(fulfillmentHold: $fulfillmentHold, id: $id) {
        fulfillmentOrder {
            id
            status
            requestStatus
            fulfillmentHolds {
                reason
                reasonNotes
            }
        }
        remainingFulfillmentOrder {
            id
        }
        userErrors {
            code
            field
            message
        }
    }
}
